from __future__ import annotations

import base64
import hashlib
import json
import os
import secrets
from pathlib import Path

from cryptography.exceptions import InvalidTag
from cryptography.hazmat.primitives.ciphers.aead import AESGCM


class VaultError(RuntimeError):
    pass


class PasswordVault:
    AAD = b"trowser-password-vault-v1"

    def __init__(self, path: Path | None = None) -> None:
        self.path = path or (
            Path.home() / ".local" / "share" / "trowser" / "passwords.vault"
        )
        self._key: bytes | None = None
        self._entries: list[dict[str, str]] = []

    @property
    def exists(self) -> bool:
        return self.path.exists()

    @property
    def unlocked(self) -> bool:
        return self._key is not None

    @staticmethod
    def _derive(master_password: str, salt: bytes) -> bytes:
        if len(master_password) < 8:
            raise VaultError("Master password must be at least 8 characters.")
        return hashlib.scrypt(
            master_password.encode(),
            salt=salt,
            n=2**15,
            r=8,
            p=1,
            dklen=32,
            maxmem=64 * 1024 * 1024,
        )

    def create(self, master_password: str) -> None:
        if self.exists:
            raise VaultError("A password vault already exists.")
        salt = secrets.token_bytes(16)
        self._key = self._derive(master_password, salt)
        self._entries = []
        self._write(salt)

    def unlock(self, master_password: str) -> None:
        if not self.exists:
            self.create(master_password)
            return
        try:
            envelope = json.loads(self.path.read_text(encoding="utf-8"))
            salt = base64.b64decode(envelope["salt"])
            nonce = base64.b64decode(envelope["nonce"])
            ciphertext = base64.b64decode(envelope["ciphertext"])
            key = self._derive(master_password, salt)
            plaintext = AESGCM(key).decrypt(nonce, ciphertext, self.AAD)
            entries = json.loads(plaintext)
        except (KeyError, ValueError, json.JSONDecodeError, InvalidTag) as error:
            raise VaultError("Wrong master password or damaged vault.") from error
        self._key = key
        self._entries = entries

    def entries(self) -> list[dict[str, str]]:
        if not self.unlocked:
            raise VaultError("Unlock the vault first.")
        return [dict(entry) for entry in self._entries]

    def add(self, site: str, username: str, password: str) -> None:
        if not self.unlocked:
            raise VaultError("Unlock the vault first.")
        if not site or not password:
            raise VaultError("Site and password are required.")
        self._entries.append(
            {
                "id": secrets.token_hex(8),
                "site": site,
                "username": username,
                "password": password,
            }
        )
        self._save()

    def remove(self, entry_id: str) -> None:
        if not self.unlocked:
            raise VaultError("Unlock the vault first.")
        self._entries = [entry for entry in self._entries if entry["id"] != entry_id]
        self._save()

    def lock(self) -> None:
        self._key = None
        self._entries = []

    def _save(self) -> None:
        envelope = json.loads(self.path.read_text(encoding="utf-8"))
        self._write(base64.b64decode(envelope["salt"]))

    def _write(self, salt: bytes) -> None:
        if self._key is None:
            raise VaultError("Unlock the vault first.")
        nonce = secrets.token_bytes(12)
        plaintext = json.dumps(self._entries, separators=(",", ":")).encode()
        ciphertext = AESGCM(self._key).encrypt(nonce, plaintext, self.AAD)
        envelope = {
            "version": 1,
            "kdf": "scrypt",
            "salt": base64.b64encode(salt).decode(),
            "nonce": base64.b64encode(nonce).decode(),
            "ciphertext": base64.b64encode(ciphertext).decode(),
        }
        self.path.parent.mkdir(parents=True, exist_ok=True)
        temporary = self.path.with_suffix(".tmp")
        temporary.write_text(json.dumps(envelope), encoding="utf-8")
        os.chmod(temporary, 0o600)
        temporary.replace(self.path)
